      "n": 34,
      "column": "left",
      "text": "No Aſeina ta Gisonite- \nra Behrneem bija : Jonatans/ \nSagea Dehls/ tas Arariteriß."
    },
    {
      "n": 35,
      "column": "left",
      "text": "Akijamß/ Sakara Dehls/ \ntas Arariteriß. Eliwals/ Ura \nDehls."
    },
    {
      "n": 36,
      "column": "left",
      "text": "Ewers/ tas Maſeratite- \nriß. Akijuß/ tas Peloniteriß."
    },
    {
      "n": 37,
      "column": "left",
      "text": "Ezrus/ tas Karmeliteriß. \nNaērajus/ Aſbaja Dehls."
    },
    {
      "n": 38,
      "column": "left",
      "text": "Joēß/ Nahtana Brahlis. \nMibearß/ Agra Dehls."
    },
    {
      "n": 39,
      "column": "left",
      "text": "Zeletß/ tas Ammonite- \nriß. Nakerajuß/ tas Berotite- \nriß / Joaba / Zerujas Dehla \nBrunnu-Neffejeß."
    },
    {
      "n": 40,
      "column": "left",
      "text": "Jrus/tas Jetriteriß. Ga- \nrebuß/ tas Jetriteriß."
    },
    {
      "n": 41,
      "column": "left",
      "text": "Urijuß/ tas Eetiteriß. Sa- \nbads/ Akelaja Dehls."
    },
    {
      "n": 42,
      "column": "left",
      "text": "Adinus/ Sisus Dehls/ \ntas Ruhbeniteriß / to Ruhbeni- \nteru Wirfneekß / tatschu pahr \nwixan bija wehl trīhsdefinitis."
    },
    {
      "n": 43,
      "column": "left",
      "text": "Anans/ Māēka Dehls / \nun Josawats/ tas Matoniteriß."
    },
    {
      "n": 44,
      "column": "left",
      "text": "Usijuß / tas Astratiteriß. \nSamus un Jajels Otama ta A- \nroēritera Dehlt."
    },
    {
      "n": 45,
      "column": "left",
      "text": "Jediaelß/ Simruß Dehls/ \nun Joūß wixan Brahlis/ tas Ti- \nziteriß."
    },
    {
      "n": 46,
      "column": "right",
      "text": "Eliēß/ tas Maewiteri \nun Jeribajinß/ un Josawiju \nElnāāma Dehli. Un Jetnuß \nMoabiteriß."
    },
    {
      "n": 47,
      "column": "right",
      "text": "Eliēß/ un Obedß/ un Je- \nestēß no Mezobajas."
    },
    {
      "n": 1,
      "column": "right",
      "text": "N schee irr/ kas \nDahwida nahze us \nlagu/kad tas wehl Sa- \nla Riſa Dehla pehz farwrup t- \nrejahs. Un tee bija arridsan ste- \nteem Warreneem/ kas Karrā \nPaligeem bija."
    },
    {
      "n": 2,
      "column": "right",
      "text": "Apbrunnōti ar Stohpe- \ntsmahziti ar Akmixeem pa la- \nun pa kreifo Rohfu mehtaht/ \nar Bultahm un Stohpu fcha- \nTee bija no Saula Brahtee \nno Benjaminza."
    },
    {
      "n": 3,
      "column": "right",
      "text": "Tas augstakajs bija A- \nsers un Joas/ Sāāma ta Gib- \ntitera Behrni / pehz to Je- \nun Pelets/ Asinaweta Behr- \nun Barakus/ un Jeus tas D- \ntotiteriß."
    },
    {
      "n": 4,
      "column": "right",
      "text": "Un Jesinajus tas Gibec- \nteris bija weens warrens st- \ntrihsdesmiteem / un pahr tri- \ndesmiteem eezelts. Un Jere- \njus/ un Jaēiēß / un Jāāna- \nun Josabadß tas Gederaticer-"
    },
    {
      "n": 5,
      "column": "right",
      "text": "Eleuſajus / un Jerimo"
    }
